class Board:
    def __init__(self):
        self.grid = np.zeros((8, 8), dtype=object)
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.grid[row][col] = Piece("black")
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece("white")

    def print_board(self):
        for row in self.grid:
            print(' '.join(f"{p.symbol if p else '.'}" for p in row))

class Piece:
    def __init__(self, color):
        self.color = color
        self.symbol = 'K' if color == 'black' else 'k'

    def is_king(self):
        return False

    def make_king(self):
        if self.color == 'black':
            self.symbol = 'K'
        else:
            self.symbol = 'k'
```

